  },
  steps: [
    {
      target: '[data-tour="user-dashboard-anchor"]',
      title: '用量展示',
      content:
        '关注CodeMaker个人用量，合理使用工具',
      placement: 'bottom',
      disableBeacon: true,
      // 在支持的 IDE 中显示
      showWhen: isSupportedIDE,
    } as TourStep,
  ],
};

