            onSelect={updateCursorPosition}
            onMouseUp={updateCursorPosition}
            onBlur={onBlur}
            onFocus={onCustomFocus}
            onScroll={handleScroll}
            onKeyDown={handleKeyDown}
            onPaste={onCustomPaste}
            onChange={debounce(onCustomChange, 300)}
          />
        </React.Fragment>
      )}
    </Box>
  )
}

