  }, [postMessage, toolCallId, updateChatApplyItem])

  return <div className="markdown-body">
    <Box bg="answerBgColor">
      <Box
        h="28px"
        display="flex"
        alignItems="center"
        px="2"
        bg="answerBgColor"
        border="1px"
        borderColor="customBorder"
        borderTopRadius="8px"
        color="text.default"
        fontSize="12px"
      >
        <Box display="flex" alignItems="center" overflow="hidden" minWidth="0" flex="1">
          <IconButton
            aria-label="展开/折叠"
            size="md"
            variant="link"
            icon={isExpanded ? <MdExpandLess /> : <MdExpandMore />}
            onClick={() => setIsExpanded(!isExpanded)}
            minW="18px"
            h="24px"
            p={0}
          />
          <Tooltip label={displayedFilePath} placement="top">
            <Box
              color="blue.300"
              cursor="pointer"
              maxWidth="100%"
              overflow="hidden"
              textOverflow="ellipsis"
