+
+  // 只有当前消息组正在流式输出时不合并，其他情况都合并
+  const shouldMerge = !(isLatest && (isStreaming || isProcessing));
+
+  // 合并连续的包含 read_file 的消息
+  const mergedMessages = useMemo(() => {
