+    let currentReadFileGroup: ChatMessage[] = [];
+    let currentReadFileIndices: number[] = [];
+    let currentToolCategory: 'list' | 'read' | 'search' | null = null; // 记录当前组的工具类别
+
+    messages.forEach((message, index) => {
