                </Box>
              </HStack>

              {/* Step 2 */}
              <HStack align="flex-start" spacing={3}>
                <Circle size="20px" bg={stepNumberBg} color={stepNumberColor} fontSize="xs" fontWeight="bold" mt={0.5}>
                  2
