  // const isShowTip = React.useMemo(() => {
  //   return (
  //     length! >= MAX_SHOW_TIP_NUM &&
  //     !sessionIDs.includes(currentSession?._id || '')
  //   );
  // }, [currentSession, sessionIDs, length]);

  const { data, isLoading } = useService(requestChatSessions, {
