      const attach = useChatAttach.getState().attachs;
      const runnerExtends = usePluginApp.getState().runnerExtends;
      const data = {
        task_id: userInputMessage?.id,
        plugin_app: { ...runner, extends: runnerExtends },
        prompt: content,
        attachs:
          attach?.attachType === AttachType.File
            ? {
              file: attach,
            }
            : null,
        messages: [
